/**
 * Email notification adapter.
 *
 * Delivers notifications via email with template rendering and
 * recipient resolution. Uses a pluggable transport for actual delivery,
 * enabling real SMTP/API sends in production and in-memory capture in tests.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A rendered email ready for transport.
 */
export interface RenderedEmail {
  to: string;
  from: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Transport interface for sending rendered emails.
 * Implement this for SMTP, SendGrid, SES, etc.
 */
export interface EmailTransport {
  send(email: RenderedEmail): Promise<{ success: boolean; error?: string }>;
}

/**
 * Configuration for the EmailAdapter.
 */
export interface EmailAdapterConfig {
  /** Sender address for outgoing emails */
  fromAddress: string;
  /** Optional transport — defaults to in-memory logging transport */
  transport?: EmailTransport;
}

/**
 * Email templates keyed by a template name derived from notification metadata.
 * Each template receives the payload and returns { subject, html, text }.
 */
type TemplateRenderer = (payload: NotificationPayload) => {
  subject: string;
  html: string;
  text: string;
};

const TEMPLATES: Record<string, TemplateRenderer> = {
  order_confirmation: (payload) => ({
    subject: payload.subject,
    html: `<h1>Order Confirmation</h1><p>${escapeHtml(payload.body)}</p>`,
    text: `Order Confirmation\n\n${payload.body}`,
  }),
  order_status_update: (payload) => ({
    subject: payload.subject,
    html: `<h1>Order Update</h1><p>${escapeHtml(payload.body)}</p>`,
    text: `Order Update\n\n${payload.body}`,
  }),
  welcome: (payload) => ({
    subject: payload.subject,
    html: `<h1>Welcome!</h1><p>${escapeHtml(payload.body)}</p>`,
    text: `Welcome!\n\n${payload.body}`,
  }),
  default: (payload) => ({
    subject: payload.subject,
    html: `<p>${escapeHtml(payload.body)}</p>`,
    text: payload.body,
  }),
};

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Validates that a recipient string looks like a valid email address.
 */
function isValidEmail(recipient: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(recipient);
}

/**
 * Default in-memory transport that captures sent emails for inspection.
 */
export class InMemoryTransport implements EmailTransport {
  private sent: RenderedEmail[] = [];

  async send(email: RenderedEmail): Promise<{ success: boolean; error?: string }> {
    this.sent.push(email);
    return { success: true };
  }

  getSentEmails(): RenderedEmail[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private fromAddress: string;
  private transport: EmailTransport;
  private sentEmails: Array<{ payload: NotificationPayload; rendered: RenderedEmail; sentAt: Date }> = [];

  constructor(config?: EmailAdapterConfig) {
    this.fromAddress = config?.fromAddress ?? 'noreply@taskflow.example.com';
    this.transport = config?.transport ?? new InMemoryTransport();
  }

  /**
   * Resolve and validate the recipient from the payload.
   * Returns the validated email address or null if invalid.
   */
  resolveRecipient(payload: NotificationPayload): string | null {
    const recipient = payload.recipient.trim().toLowerCase();
    if (!isValidEmail(recipient)) {
      this.logger.warn(`Invalid email recipient: ${payload.recipient}`);
      return null;
    }
    return recipient;
  }

  /**
   * Render the email using the appropriate template.
   * Selects template based on metadata.templateName or falls back to 'default'.
   */
  renderEmail(payload: NotificationPayload): RenderedEmail {
    const templateName = payload.metadata?.templateName ?? 'default';
    const renderer = TEMPLATES[templateName] ?? TEMPLATES['default'];
    const rendered = renderer(payload);

    return {
      to: payload.recipient,
      from: this.fromAddress,
      subject: rendered.subject,
      html: rendered.html,
      text: rendered.text,
    };
  }

  /**
   * Send a notification via email.
   *
   * 1. Resolves and validates the recipient
   * 2. Renders the email using the matching template
   * 3. Delivers via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const resolved = this.resolveRecipient(payload);
    if (!resolved) {
      return {
        success: false,
        channel: 'email',
        error: `Invalid recipient email: ${payload.recipient}`,
      };
    }

    const normalizedPayload = { ...payload, recipient: resolved };
    const rendered = this.renderEmail(normalizedPayload);

    try {
      const result = await this.transport.send(rendered);

      if (result.success) {
        this.sentEmails.push({ payload: normalizedPayload, rendered, sentAt: new Date() });
        this.logger.info(`Email sent to ${resolved}: ${rendered.subject}`);
        return {
          success: true,
          channel: 'email',
          deliveredAt: new Date(),
        };
      }

      this.logger.error(`Email delivery failed for ${resolved}: ${result.error}`);
      return {
        success: false,
        channel: 'email',
        error: result.error ?? 'Transport delivery failed',
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`Email transport error for ${resolved}: ${message}`);
      return {
        success: false,
        channel: 'email',
        error: `Transport error: ${message}`,
      };
    }
  }

  /**
   * Get all successfully sent emails. Useful for testing.
   */
  getSentEmails(): Array<{ payload: NotificationPayload; rendered: RenderedEmail; sentAt: Date }> {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

