        subject: 'Order Update: order-1',
        body: 'Status changed from pending to confirmed.',
        metadata: { templateName: 'order_status_update' },
      });
      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).toContain('<h1>Order Update</h1>');
      expect(rendered.text).toContain('Order Update');
    });

    it('should use welcome template', () => {
      const payload = makePayload({
        subject: 'Welcome to TaskFlow',
        body: 'Welcome aboard!',
        metadata: { templateName: 'welcome' },
      });
      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).toContain('<h1>Welcome!</h1>');
    });

    it('should fall back to default for unknown template', () => {
      const payload = makePayload({
        metadata: { templateName: 'nonexistent' },
      });
      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).not.toContain('<h1>');
      expect(rendered.text).toBe('Test body content');
    });

    it('should escape HTML in body', () => {
      const payload = makePayload({ body: '<script>alert("xss")</script>' });
      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).not.toContain('<script>');
      expect(rendered.html).toContain('&lt;script&gt;');
    });
  });

  describe('send', () => {
    it('should send a valid email successfully', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      const sent = transport.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.from).toBe('sender@taskflow.example.com');
    });

    it('should fail for an invalid recipient', async () => {
      const payload = makePayload({ recipient: 'bad-email' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid recipient email');
      expect(transport.getSentEmails()).toHaveLength(0);
    });

    it('should handle transport failure', async () => {
      const failTransport: EmailTransport = {
        async send() {
          return { success: false, error: 'SMTP connection refused' };
        },
      };
      const failAdapter = new EmailAdapter({
        fromAddress: 'sender@taskflow.example.com',
        transport: failTransport,
      });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should handle transport exception', async () => {
      const throwTransport: EmailTransport = {
        async send() {
          throw new Error('Network timeout');
        },
      };
      const throwAdapter = new EmailAdapter({
        fromAddress: 'sender@taskflow.example.com',
        transport: throwTransport,
      });

      const result = await throwAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('Transport error: Network timeout');
    });

    it('should record sent emails for inspection', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'bob@example.com', subject: 'Second' }));

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.payload.recipient).toBe('alice@example.com');
      expect(sent[1]?.payload.recipient).toBe('bob@example.com');
      expect(sent[1]?.rendered.subject).toBe('Second');
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('defaults', () => {
    it('should use default from address and in-memory transport', async () => {
      const defaultAdapter = new EmailAdapter();
      const result = await defaultAdapter.send(makePayload());

      expect(result.success).toBe(true);
      const sent = defaultAdapter.getSentEmails();
      expect(sent[0]?.rendered.from).toBe('noreply@taskflow.example.com');
    });
  });
});

describe('InMemoryTransport', () => {
  it('should capture and clear sent emails', async () => {
    const transport = new InMemoryTransport();
    const email: RenderedEmail = {
      to: 'a@b.com',
      from: 'x@y.com',
      subject: 'hi',
      html: '<p>hi</p>',
      text: 'hi',
    };

    await transport.send(email);
    expect(transport.getSentEmails()).toHaveLength(1);

    transport.clear();
    expect(transport.getSentEmails()).toHaveLength(0);
  });
});
